const a=JSON.parse(`[{"number":10,"part":2,"slug":"maruf-al-karkhi","name":"Maruf al-Karkhi","arabicName":"معروف الكرخي","metadata":{"fullName":"Abu Mahfuz Maruf ibn Firuz al-Karkhi","born":"Karkh (a quarter of Baghdad)","died":"200 AH / 815 CE, Baghdad","sufiOrder":"Pre-tariqa era; key link in the Qadiri silsila","titles":"One of the Abdal (Substitutes)","teachers":"Dawud al-Tai; also said to have met Ali al-Rida (8th Shi'i Imam)","notableStudents":"Sari al-Saqati","burial":"Baghdad — his tomb became a famous site for answered prayers"},"ceYear":0,"biography":["Maruf al-Karkhi is a pivotal figure in the chain of Sufi transmission. Born to non-Muslim (some sources say Christian or Sabian) parents in the Karkh quarter of Baghdad, he converted to Islam — according to tradition, at the hands of Ali al-Rida, the eighth Imam of the Shi'a. His parents subsequently embraced Islam as well. This story of conversion gives Maruf a unique position: he represents the transformative power of Islam's spiritual dimension.","Maruf was a man of few words but immense spiritual presence. He studied under Dawud al-Tai and became the teacher of Sari al-Saqati, who in turn taught Junaid al-Baghdadi. This chain — Dawud → Maruf → Sari → Junaid — is one of the golden chains of Sufi transmission."],"keyTeachings":["Maruf taught that love of God is not something that can be learned from books but is a gift that God places in the heart of whomever He wills. He emphasized simplicity, sincerity, and direct experience of the Divine."],"famousStories":[{"title":"The Two Boys","content":"Once, two boys were fighting. Maruf approached and gave a sweet to each of them. Someone asked: \\"Did you have those sweets with you?\\" He said: \\"No, I asked God for them and He provided.\\" He was asked: \\"What prompted this?\\" He replied: *\\"I could not bear to see creation in conflict.\\"*"},{"title":"The Answered Prayers","content":"It was so widely known that prayers at Maruf's tomb were answered that Imam Ahmad ibn Hanbal — the great hadith scholar — was asked about it. He confirmed: *\\"Maruf al-Karkhi is a proven means of intercession with God.\\"* This endorsement from the founder of the Hanbali school is significant, given that school's later association with opposition to certain Sufi practices."}],"legacy":["Maruf al-Karkhi's primary legacy is his position in the silsila — connecting the early ascetics to the great Baghdad school of Sufism. His tomb in Baghdad remained a place of pilgrimage and answered prayers for centuries. Through Sari al-Saqati and Junaid, his spiritual influence permeated the entire tradition."],"sources":[{"label":"Wikipedia – Ma'ruf al-Karkhi","url":"https://en.wikipedia.org/wiki/Ma%27ruf_al-Karkhi","description":"Article on the Baghdad saint, his conversion from a non-Muslim family, his discipleship under Dawud al-Tai, and his pivotal role in the Sufi chain","unverified":false},{"label":"Wikipedia – Ali al-Ridha","url":"https://en.wikipedia.org/wiki/Ali_al-Rida","description":"The eighth Imam of the Twelver Shia at whose hands Maruf is said to have converted to Islam","unverified":false},{"label":"Wikipedia – Sari al-Saqati","url":"https://en.wikipedia.org/wiki/Sari_al-Saqati","description":"Maruf's primary student and the teacher of Junaid al-Baghdadi","unverified":false},{"label":"Classical text","url":null,"description":"detailed biography of Maruf al-Karkhi, including accounts of answered prayers at his tomb","unverified":false}]},{"number":11,"part":2,"slug":"dhul-nun-al-misri","name":"Dhul-Nun al-Misri","arabicName":"ذو النون المصري","metadata":{"fullName":"Abu al-Fayd Thawban ibn Ibrahim Dhul-Nun al-Misri (also called al-Ikhmimi)","born":"c. 180 AH / 796 CE, Ikhmim (Akhmim), Upper Egypt","died":"245 AH / 859 CE, Fustat (Old Cairo)","sufiOrder":"Pre-tariqa era","titles":"\\"The Lord of the Fish\\" (Dhul-Nun — a reference to the Prophet Yunus), Master of Ma'rifa","teachers":"Various Egyptian scholars; also attributed with learning from hermits and ancient Egyptian sources","notableStudents":"Many, transmitted his teachings across Egypt and beyond"},"ceYear":796,"biography":["Dhul-Nun al-Misri — \\"The Lord of the Fish\\" — was one of the most fascinating and enigmatic figures of early Sufism. Born in Upper Egypt to a Nubian family, he combined deep Islamic scholarship with a mysterious connection to Egypt's ancient heritage. Some sources credit him with knowledge of hieroglyphics and ancient Egyptian wisdom, though this may be legendary accretion.","Dhul-Nun's great contribution to Sufi thought was his articulation of ma'rifa (gnosis/mystical knowledge) as distinct from ordinary 'ilm (knowledge). He taught that ma'rifa is a direct, experiential knowledge of God that transcends rational understanding — a light that God casts into the heart. This was revolutionary: it established that the Sufi path leads to a form of knowledge that is qualitatively different from book-learning.","He was brought to Baghdad in chains, accused of heresy (zandaqa) by the religious establishment of Egypt. However, when he was brought before the Abbasid caliph al-Mutawakkil and spoke, the caliph was so moved by his words that he wept and released him with honor."],"keyTeachings":["Dhul-Nun distinguished between three levels of knowledge: the knowledge of the common people (through hearing and tradition), the knowledge of the scholars (through proof and reasoning), and the knowledge of the saints (through direct experience and unveiling). Only the last is true ma'rifa. He said: *\\"The gnostic (arif) becomes more humble with every increase in knowledge, more compassionate with every increase in spiritual station.\\"*"],"famousStories":[{"title":"The Trial in Baghdad","content":"When Dhul-Nun was brought before the caliph in chains, accused of heresy, he spoke of the love of God with such eloquence that the caliph and his entire court wept. Al-Mutawakkil declared him innocent and ordered his honorable return to Egypt. On the way back, a woman called out to him: \\"Is it not enough that they carried you to Him that now He carries you back?\\""},{"title":"The Scorpion and the Turtle","content":"Dhul-Nun once saw a scorpion struggling in a stream. A turtle appeared, carried the scorpion across on its back, and deposited it safely on the other shore. Then the scorpion climbed down and stung a sleeping man — who turned out to have a venomous snake about to bite him. The sting woke the man and saved his life. Dhul-Nun wept and said: *\\"God provides means within means. If He arranges a scorpion to save a sleeping man, how will He not provide for His devoted servants?\\"*"},{"title":"His Funeral","content":"When Dhul-Nun died, a mysterious inscription appeared on his forehead: *\\"This is the beloved of God, who died in love of God, slain by God.\\"* Birds were seen circling his funeral bier, shading the procession from the sun."}],"legacy":["Dhul-Nun al-Misri established the concept of ma'rifa as central to the Sufi path, influencing all subsequent mystical thought. He is also considered a key figure in the development of the Sufi understanding of states (ahwal) — transient spiritual experiences granted by God — as distinct from stations (maqamat) — permanent spiritual ranks earned through effort."],"sources":[{"label":"Wikipedia – Dhu al-Nun al-Misri","url":"https://en.wikipedia.org/wiki/Dhul-Nun_al-Misri","description":"Article on the Egyptian Sufi master, his doctrine of ma'rifa, his trial before the Abbasid caliph, and his legacy","unverified":false},{"label":"Wikipedia – Akhmim","url":"https://en.wikipedia.org/wiki/Akhmim","description":"The Upper Egyptian city (ancient Panopolis) where Dhul-Nun was born; known for its ancient Egyptian heritage","unverified":false},{"label":"Wikipedia – Al-Mutawakkil","url":"https://en.wikipedia.org/wiki/Al-Mutawakkil","description":"The Abbasid caliph before whom Dhul-Nun was brought in chains and who freed him after being moved by his words","unverified":false},{"label":"Classical text","url":null,"description":"contains the primary narrative account of Dhul-Nun's trial, his mystical sayings, and the inscription on his forehead at death","unverified":false}]},{"number":12,"part":2,"slug":"bayazid-bistami","name":"Bayazid Bistami","arabicName":"بايزيد بسطامي","metadata":{"fullName":"Abu Yazid Tayfur ibn Isa ibn Surushan al-Bistami","born":"c. 188 AH / 804 CE, Bistam (Khorasan, present-day Iran)","died":"261 AH / 874 CE (or 234 AH — dates disputed), Bistam","sufiOrder":"Pre-tariqa era; spiritual ancestor of the \\"intoxicated\\" (sukri) school","titles":"Sultan al-Arifin (Sultan of the Gnostics), Tayfur","teachers":"Abu Ali al-Sindi (who taught him the concept of fana', possibly from Indian influences)","Legacy":"Pioneer of ecstatic Sufism and the concept of fana' (self-annihilation)"},"ceYear":804,"biography":["Abu Yazid (Bayazid) Bistami is one of the most electrifying figures in the history of Islamic spirituality. Born in the small town of Bistam in northeastern Iran, he lived an outwardly unremarkable life — never leaving his hometown for long, never writing books, never founding an order. Yet his ecstatic utterances (shathiyyat) shook the foundations of Islamic mysticism and divided scholars for centuries.","Bayazid is credited with being the first Sufi to articulate the experience of fana' (annihilation of the self in God) in dramatic, shocking terms. His most famous utterance — *\\"Subhani! Ma a'zama sha'ni!\\"* (Glory be to Me! How great is My majesty!) — was understood by Sufis not as a claim to divinity but as an expression of fana': when the self is completely annihilated, only God remains, and it is God speaking through the emptied vessel of the saint.","He represents the \\"intoxicated\\" (sukri) school of Sufism, in contrast to Junaid's \\"sober\\" (sahwi) school. Where Junaid veiled mystical truths in careful language, Bayazid erupted with raw expressions of divine encounter."],"keyTeachings":["Bayazid taught that the ultimate spiritual experience is fana' — the complete dissolution of the individual self in the ocean of Divine Unity. He also articulated the concept of the mi'raj (ascension) of the saint, paralleling the Prophet's ﷺ heavenly ascension, in which the mystic journeys through spiritual realms."],"famousStories":[{"title":"\\"Subhani!\\" (Glory be to Me!)","content":"Bayazid's students once heard him cry out in ecstasy: *\\"Subhani! Ma a'zama sha'ni!\\"* — words that, on their surface, constitute blasphemy, as they are an attribute of God alone. When Bayazid returned to normal consciousness and was told what he had said, he told his students: *\\"If I say such things again, take your knives and slay me.\\"* The next time it happened, they rushed at him with knives — but their blades turned back upon themselves, as if striking at Bayazid was striking at God Himself. This story illustrates the Sufi understanding that in the state of fana', the individual has ceased to exist."},{"title":"The Spiritual Mi'raj","content":"Bayazid described a mystical ascension through the heavens in which he passed through realm after realm, until he reached a point where God said to him: \\"Ask of Me.\\" He replied: *\\"I seek nothing but You.\\"* God then said: *\\"You are Mine and I am yours.\\"* This narrative, widely transmitted in Sufi literature, established the model of the saintly mi'raj."},{"title":"The Old Woman","content":"Bayazid was once walking with his disciples when an old woman approached and asked: \\"Where is Abu Yazid?\\" He replied: \\"Who is Abu Yazid? I have been seeking Abu Yazid for thirty years and have not found him.\\" This illustrates his teaching on fana' — the true self is not the ego-self that bears a name, but the divine reality within."}],"legacy":["Bayazid Bistami's ecstatic utterances established the \\"intoxicated\\" stream of Sufism that would later flow through al-Hallaj, Rumi, and countless others. His concept of fana' became one of the pillars of Sufi metaphysics. His shrine in Bistam remains a place of pilgrimage, and virtually every discussion of Sufi states references his experience."],"sources":[{"label":"Wikipedia – Bayazid Bastami","url":"https://en.wikipedia.org/wiki/Bayazid_Bastami","description":"Article on the \\"Sultan of the Gnostics,\\" his ecstatic utterances (shathiyyat), the concept of fana', and his foundational role in the \\"intoxicated\\" school of Sufism","unverified":false},{"label":"Wikipedia – Bastam","url":"https://en.wikipedia.org/wiki/Bastam","description":"The northeastern Iranian city where Bayazid was born and died; his shrine there remains a pilgrimage site","unverified":false},{"label":"Wikipedia – Fana (Sufism)","url":"https://en.wikipedia.org/wiki/Fana_(Sufism)","description":"The central doctrine Bayazid pioneered: the annihilation of the individual self in the Divine","unverified":false},{"label":"Classical text","url":null,"description":"the fullest classical account of Bayazid's ecstatic states, his shathiyyat, and his spiritual mi'raj narrative","unverified":false}]},{"number":13,"part":2,"slug":"sari-al-saqati","name":"Sari al-Saqati","arabicName":"سري السقطي","metadata":{"fullName":"Abu al-Hasan Sari ibn al-Mughallas al-Saqati","born":"c. 155 AH / 772 CE, Baghdad","died":"253 AH / 867 CE, Baghdad","sufiOrder":"Pre-tariqa era; uncle and teacher of Junaid","titles":"The First to Systematically Teach Tawhid in Baghdad","teachers":"Maruf al-Karkhi, Habib al-Ajami","notableStudents":"Junaid al-Baghdadi (his nephew)"},"ceYear":772,"biography":["Sari al-Saqati was a merchant in the Baghdad market and the spiritual link between Maruf al-Karkhi and Junaid al-Baghdadi — thus occupying a critical position in the golden chain of Sufi transmission. His surname \\"al-Saqati\\" derives from his profession as a dealer in secondhand goods (saqat).","His transformation from merchant to mystic is attributed to the influence of Maruf al-Karkhi. After embracing the spiritual path, Sari became renowned for his scrupulousness in avoiding doubtful income and for his deep understanding of tawhid (divine unity) and ikhlas (sincerity). He was the first in Baghdad to publicly discourse on the subtle spiritual states (ahwal) and the realities of tawhid, opening the door for the more systematic teachings of his nephew Junaid."],"keyTeachings":["Sari defined sincerity (ikhlas) with devastating precision: *\\"I have been examining my sincerity for thirty years and found it to be insincere.\\"* This encapsulates the Sufi understanding that even sincerity itself can become a subtle form of ego if one takes pride in being sincere."],"famousStories":[{"title":"The Baghdad Market Fire","content":"When a great fire swept through the Baghdad market, destroying the shops of many merchants, someone came running to tell Sari that his shop had been spared. He said: *\\"Alhamdulillah\\"* (Praise be to God). Then he reflected and was horrified at himself: *\\"I praised God that my shop was spared while my brothers' shops were destroyed. This is selfishness.\\"* He spent years repenting for this momentary thought, considering it a spiritual failing."},{"title":"Teaching Junaid","content":"When his nephew Junaid was young, Sari used to take him to the circles of learning. One day, the scholars were discussing gratitude (shukr). Sari turned to the boy and asked: \\"What is gratitude, O Junaid?\\" The child replied: *\\"It is that you do not use God's blessings to disobey Him.\\"* Sari wept and said: *\\"Your portion from God is your tongue, my boy. I pray you are not tested by it.\\"*"}],"legacy":["Sari al-Saqati's principal legacy is as the bridge to Junaid — perhaps the most important figure in all of Sufism. His exacting standards of sincerity and his pioneering public discourses on tawhid in Baghdad prepared the ground for the systematic Sufi theology that Junaid would perfect."],"sources":[{"label":"Wikipedia – Sari al-Saqati","url":"https://en.wikipedia.org/wiki/Sari_al-Saqati","description":"Article on the Baghdad merchant-turned-mystic, his discipleship under Maruf al-Karkhi, and his role as teacher and uncle of Junaid al-Baghdadi","unverified":false},{"label":"Wikipedia – Junaid al-Baghdadi","url":"https://en.wikipedia.org/wiki/Junayd_of_Baghdad","description":"Sari's most celebrated student and the figure who brought his lineage to its greatest development","unverified":false},{"label":"Classical text","url":null,"description":"biographical entry on Sari al-Saqati, preserving his key sayings on sincerity and tawhid","unverified":false}]},{"number":14,"part":2,"slug":"harith-al-muhasibi","name":"Harith al-Muhasibi","arabicName":"الحارث المحاسبي","metadata":{"fullName":"Abu Abdullah al-Harith ibn Asad al-Anazi al-Muhasibi","born":"c. 165 AH / 781 CE, Basra","died":"243 AH / 857 CE, Baghdad","sufiOrder":"Pre-tariqa era","titles":"The Father of Sufi Psychology","teachers":"Various scholars of Baghdad","notableStudents":"Junaid al-Baghdadi","majorWorks":"Kitab al-Ri'aya li-Huquq Allah (Observance of the Rights of God)"},"ceYear":781,"biography":["Harith al-Muhasibi — whose name derives from muhasaba (self-accounting/self-examination) — was the pioneer of spiritual psychology in Islam. Born in Basra and active in Baghdad, he developed a rigorous method of examining one's own intentions, thoughts, and inner states with unflinching honesty. His approach was so systematic that he is sometimes called the first Sufi psychologist.","His masterwork, Kitab al-Ri'aya li-Huquq Allah, is a comprehensive manual of spiritual self-examination that analyzes the diseases of the heart — pride, envy, ostentation, self-deception — and prescribes their cures. This work had a decisive influence on Abu Hamid al-Ghazali's Ihya Ulum al-Din, written two centuries later.","Al-Muhasibi faced opposition from the traditionalist scholar Ahmad ibn Hanbal, who was suspicious of his use of dialectical reasoning (kalam) in spiritual matters. This tension foreshadowed the ongoing dialogue between Sufi and anti-Sufi scholarly camps."],"keyTeachings":["Al-Muhasibi taught that the most dangerous enemy is not the external world but the nafs (ego-self), which constantly deceives. The only remedy is constant muhasaba — calling oneself to account before God calls one to account on the Day of Judgment. He systematized the diseases of the heart and their cures in a way that anticipated modern psychology."],"famousStories":[{"title":"Ahmad ibn Hanbal's Reaction","content":"Despite opposing al-Muhasibi publicly, Ahmad ibn Hanbal is said to have secretly listened to his discourses from behind a wall. Afterward, Ahmad wept and admitted: *\\"I have never heard anyone speak about the realities of things as this man does. Yet I cannot associate with him openly.\\"* This story poignantly illustrates the tension between the scholars of hadith and the scholars of the heart."},{"title":"The Mirror of the Self","content":"Al-Muhasibi taught his students to examine every action with three questions: *\\"Why did I do it? For whom did I do it? Was God pleased with it?\\"* He called this the \\"mirror of the self\\" — and warned that most people would be horrified at what they saw if they looked honestly."}],"legacy":["Al-Muhasibi's method of muhasaba became foundational to Sufi ethics and spiritual training. His works directly influenced al-Ghazali, and through al-Ghazali, the entire Islamic world. He established that the spiritual path is not merely about ecstatic states but about the painstaking, daily work of purifying one's intentions and character."],"sources":[{"label":"Wikipedia – Al-Harith al-Muhasibi","url":"https://en.wikipedia.org/wiki/Al-Muhasibi","description":"Article on the pioneer of Sufi psychology, his method of muhasaba (self-examination), and his decisive influence on al-Ghazali","unverified":false},{"label":"Wikipedia – Ahmad ibn Hanbal","url":"https://en.wikipedia.org/wiki/Ahmad_ibn_Hanbal","description":"The hadith scholar and founder of the Hanbali school who publicly opposed yet privately respected al-Muhasibi","unverified":false},{"label":"Classical text","url":null,"description":"the foundational manual of Sufi psychology, analyzing the diseases of the heart and prescribing spiritual remedies; directly influenced al-Ghazali's *Ihya*","unverified":false}]},{"number":15,"part":2,"slug":"abu-al-qasim-al-junaid-al-baghdadi","name":"Abu al-Qasim al-Junaid al-Baghdadi","arabicName":"أبو القاسم الجنيد البغدادي","metadata":{"fullName":"Abu al-Qasim al-Junaid ibn Muhammad al-Khazzaz al-Qawariri al-Baghdadi","born":"c. 215 AH / 830 CE, Baghdad (of Persian origin from Nahawand)","died":"297 AH / 910 CE, Baghdad","sufiOrder":"Pre-tariqa era; \\"Master of the Group\\" (Sayyid al-Ta'ifa) — almost all later tariqas trace their silsila through him","titles":"Sayyid al-Ta'ifa (Master of the Group), Tawus al-Ulama (Peacock of the Scholars), Shaykh al-Mashayikh (Master of Masters)","teachers":"Sari al-Saqati (his maternal uncle), Harith al-Muhasibi, Muhammad ibn Ali al-Qassab","notableStudents":"Abu Bakr al-Shibli, Mansur al-Hallaj (briefly), Abu al-Abbas al-Nihawandi, and many others"},"ceYear":830,"biography":["If Hasan al-Basri is the trunk of the Sufi tree, then Junaid al-Baghdadi is its crown. He is universally acknowledged as the greatest master of the classical period and bears the unique title \\"Sayyid al-Ta'ifa\\" — the Master of the Entire Group — meaning the chief of all Sufis. Almost every major Sufi order traces its spiritual chain through him.","Born in Baghdad to a family of Persian origin (his father was a glass merchant — hence \\"al-Qawariri\\"), Junaid was raised by his uncle Sari al-Saqati and educated in both the exoteric sciences (he was a qualified Shafi'i jurist) and the esoteric path. He was a prodigy: his discourse on gratitude at the age of seven left his uncle in tears.","Junaid's supreme achievement was establishing the \\"sober\\" (sahwi) school of Sufism. In contrast to the ecstatic utterances of Bayazid Bistami and the public declarations of al-Hallaj, Junaid taught that the highest spiritual state is not the intoxication (sukr) of mystical union but the sobriety (sahw) that comes after it — when the mystic returns to normal consciousness while retaining the knowledge gained in ecstasy. He expressed mystical truths in careful, precise language that was defensible within orthodox theology.","He formulated the doctrine of fana' (annihilation) and baqa' (subsistence) with philosophical rigor: the mystic's ego is annihilated in God (fana'), and then God restores the mystic to a state of subsistence (baqa') in which they function in the world while being inwardly united with the Divine."],"keyTeachings":["Junaid defined tasawwuf as: *\\"God causing you to die to yourself and to live in Him.\\"* He also said: *\\"Tasawwuf is not achieved by much praying and fasting, but by the security of the heart and generosity of the soul.\\"*","His doctrine of the \\"primordial covenant\\" (mithaq) — referring to Quran 7:172 where God asked the souls, \\"Am I not your Lord?\\" and they replied \\"Yes\\" — became central to Sufi metaphysics. He taught that the spiritual path is a return to this original state of union with God."],"famousStories":[{"title":"The Seven-Year-Old's Answer","content":"When Junaid was seven years old, Sari al-Saqati took him to a gathering where the scholars were discussing gratitude (shukr). Sari asked the boy for his definition. Junaid replied: *\\"Gratitude is that you do not use the blessings of God to disobey Him.\\"* The entire assembly was silenced, and Sari wept."},{"title":"The Response to al-Hallaj","content":"When al-Hallaj was making his controversial public declarations, Junaid reportedly told him: *\\"What an opening at the wooden post awaits you.\\"* — foretelling his crucifixion. When asked whether al-Hallaj's \\"Ana al-Haqq\\" was true, Junaid is said to have replied: *\\"He spoke the truth, but what gibbet of wood that truth will cost him.\\"* Yet on another occasion, Junaid refused to sign the fatwa condemning al-Hallaj, saying: *\\"I judge only by the outward.\\"*"},{"title":"His Final Moments","content":"As Junaid lay dying, he was found reciting the Quran from the beginning. Someone asked: \\"At such a time?\\" He replied: *\\"Who is more in need of it than I, at a moment when my record of deeds is being folded up?\\"*"}],"majorWorksText":["Junaid's writings survive primarily as letters (rasa'il) and short treatises collected by his students. These include his epistle on tawhid, his letters to various disciples, and his sayings recorded in the manuals of al-Sarraj, al-Qushayri, and others."],"legacy":["Junaid al-Baghdadi's legacy is immeasurable. He defined the mainstream of Sufi thought as sober, orthodox, and rooted in the Sharia. Virtually every Sufi order passes through him in its silsila. His formulation of fana' and baqa', his insistence on combining ecstatic experience with intellectual rigor, and his integration of Sufism with mainstream Islamic scholarship set the template for all that followed."],"sources":[{"label":"Wikipedia – Junayd al-Baghdadi","url":"https://en.wikipedia.org/wiki/Junayd_of_Baghdad","description":"Comprehensive article on the \\"Master of the Group,\\" his sober school of Sufism, his formulation of fana' and baqa', and his central place in virtually every Sufi silsila","unverified":false},{"label":"Wikipedia – Mansur al-Hallaj","url":"https://en.wikipedia.org/wiki/Mansur_al-Hallaj","description":"Junaid's most controversial student; the chapter documents Junaid's cautious response to al-Hallaj's declarations","unverified":false},{"label":"Wikipedia – Quran 7:172","url":"https://en.wikipedia.org/wiki/Al-A%27raf","description":"Surah al-A'raf containing the \\"primordial covenant\\" verse (mithaq) that Junaid made central to his metaphysical doctrine","unverified":false},{"label":"Classical text","url":null,"description":"preserves extensive sayings and teachings of Junaid, including his letters and definitions of key Sufi terms","unverified":false}]},{"number":16,"part":2,"slug":"mansur-al-hallaj","name":"Mansur al-Hallaj","arabicName":"منصور الحلاج","metadata":{"fullName":"Abu al-Mughith al-Husayn ibn Mansur al-Hallaj","born":"c. 244 AH / 858 CE, Tur (or Bayda), Fars, Persia","died":"26 Dhul-Qi'da 309 AH / 26 March 922 CE, Baghdad (executed)","sufiOrder":"Pre-tariqa era; studied under Junaid, Amr al-Makki, and others","titles":"The Martyr of Mystical Love","teachers":"Sahl al-Tustari, Amr ibn Uthman al-Makki, Junaid al-Baghdadi (briefly)"},"ceYear":858,"biography":["No figure in the history of Islamic mysticism is more controversial, more debated, or more passionately loved and reviled than Mansur al-Hallaj. His life and death form the great dramatic crisis of classical Sufism — a story of divine love, public witness, political intrigue, and ultimate martyrdom that has haunted the Islamic imagination for over a millennium.","Born in the province of Fars to a cotton-carder (hallaj), he studied under three great masters: Sahl al-Tustari, Amr ibn Uthman al-Makki, and Junaid al-Baghdadi. But he was too intense, too transparent for the cautious world of the Baghdad Sufis. His masters distanced themselves from him — Junaid reportedly said he would come to a bad end.","Al-Hallaj broke the unwritten code of Sufi discretion. While other masters spoke of mystical truths in guarded language and within closed circles, al-Hallaj took to the streets and marketplaces, publicly declaring: *\\"Ana al-Haqq!\\"* (I am the Truth! / I am God!). He traveled to India and Central Asia, performed what appeared to be miracles, and gathered a massive following among the common people.","His public preaching and growing influence alarmed both the religious establishment and the Abbasid political authorities. After years of trials, imprisonment, and political machinations, al-Hallaj was sentenced to death. On 26 Dhul-Qi'da 309 AH (March 26, 922 CE), he was publicly flogged, his hands and feet were cut off, he was crucified, and finally beheaded. His body was burned and his ashes thrown into the Tigris."],"keyTeachings":["Al-Hallaj taught that the goal of the spiritual path is complete union (ittihad) with God — a teaching that his critics called hulul (incarnationism). His supporters, however, interpreted his \\"Ana al-Haqq\\" as an expression of fana' — when the self is annihilated, only the Divine remains, and any utterance comes from God, not the extinguished ego.","His theology of love held that the lover must be completely consumed by the Beloved, like a moth in a flame. He wrote: *\\"I am He whom I love, and He whom I love is I. We are two spirits dwelling in one body.\\"*"],"famousStories":[{"title":"\\"Ana al-Haqq\\"","content":"The utterance that would cost him his life. When al-Hallaj declared \\"I am the Truth\\" (al-Haqq being one of the ninety-nine names of God), it was heard by different ears differently. To the jurists, it was blasphemy. To the Sufis, it was the highest expression of fana'. Junaid, when asked, said: *\\"He spoke from the station of fana', where nothing remains but God.\\"* Centuries later, Rumi would defend al-Hallaj extensively in the Masnavi."},{"title":"The Execution","content":"At his execution, al-Hallaj is reported to have laughed and danced in his chains. When asked why, he said: *\\"It is the coquetry of the Beloved.\\"* As he was being flogged, he prayed: *\\"O God, forgive these people. If You had shown them what You have shown me, they would not do this. And if You had hidden from me what You have hidden from them, I would not suffer this.\\"* His last words, as recorded by multiple sources, were a prayer for his executioners."},{"title":"The Blood Writing","content":"According to tradition, when al-Hallaj's blood fell to the ground during his execution, the drops formed the word \\"Allah.\\" When his ashes were thrown into the Tigris, the river swelled and began to flood, until al-Hallaj's cloak was placed on the water, and it calmed."}],"majorWorksText":["Al-Hallaj left behind a collection of poetry (Diwan al-Hallaj), fragments of prose works, and his masterpiece Kitab al-Tawasin — a mystical text of extraordinary density and beauty, including meditations on the Prophet Muhammad ﷺ, the moth and the flame, and the nature of divine love."],"legacy":["Al-Hallaj's execution did not silence his message — it amplified it across the centuries. He became the supreme symbol of the mystic's willingness to die for truth. Attar devoted extensive sections to him in Tadhkirat al-Awliya. Rumi defended and celebrated him. The Pakistani philosopher Muhammad Iqbal invoked him. The French scholar Louis Massignon dedicated his life's work to studying him. Al-Hallaj remains the most discussed, most controversial, and most beloved martyr in the history of Islamic mysticism."],"sources":[{"label":"Wikipedia – Mansur al-Hallaj","url":"https://en.wikipedia.org/wiki/Mansur_al-Hallaj","description":"Comprehensive article on the martyr of mystical love, his declaration of \\"Ana al-Haqq,\\" his trial, execution on 26 March 922 CE, and his enduring legacy across Islamic civilization","unverified":false},{"label":"Wikipedia – Louis Massignon","url":"https://en.wikipedia.org/wiki/Louis_Massignon","description":"The French Orientalist whose life's scholarship was devoted to al-Hallaj; his study *La Passion de Hallaj* is the definitive modern work","unverified":false},{"label":"Classical text","url":null,"description":"al-Hallaj's own mystical text; includes meditations on the Prophet ﷺ, the nature of divine love, and the parable of the moth and flame","unverified":false},{"label":"Classical text","url":null,"description":"the fullest classical hagiographic account of al-Hallaj's life, teachings, and martyrdom","unverified":false}]},{"number":17,"part":2,"slug":"abu-bakr-al-shibli","name":"Abu Bakr al-Shibli","arabicName":"أبو بكر الشبلي","metadata":{"fullName":"Abu Bakr Dulaf ibn Jahdar al-Shibli","born":"247 AH / 861 CE, Samarra (or Baghdad)","died":"334 AH / 946 CE, Baghdad","sufiOrder":"Pre-tariqa era; student of Junaid","titles":"The Madman of God","teachers":"Junaid al-Baghdadi","Background":"Former high-ranking government official (chamberlain of the caliph)"},"ceYear":861,"biography":["Abu Bakr al-Shibli was one of the most dramatic figures of the Baghdad school of Sufism — a former high-ranking court official who abandoned his prestigious career for the path of divine love, and whose subsequent spiritual states were so intense that he was repeatedly confined to the madhouse (bimaristan).","Before his conversion, al-Shibli served as the chamberlain (hajib) of the Abbasid court — a position of enormous power and prestige. His transformation came suddenly and completely, and he became a devoted disciple of Junaid al-Baghdadi. But where Junaid counseled sobriety, al-Shibli was consumed by ecstatic states that defied social convention."],"keyTeachings":["Al-Shibli expressed his teachings primarily through paradoxes, dramatic actions, and ecstatic utterances rather than systematic discourse. He taught that true tawhid (divine unity) leaves no room for the self — and he lived this principle to its extreme."],"famousStories":[{"title":"At al-Hallaj's Execution","content":"When al-Hallaj was being led to his execution, the crowd pelted him with stones. It is said that al-Hallaj bore the stones without flinching but cried out when al-Shibli threw a rose. When asked why the rose hurt more than the stones, al-Hallaj replied: *\\"Because they do not know, but he knows.\\"* — meaning the cruelty of a friend who understands the truth is more painful than the ignorance of enemies."},{"title":"The Madhouse","content":"Al-Shibli's ecstatic states were so intense that he was repeatedly committed to the bimaristan (hospital/asylum). When visitors came, he would throw stones at them, saying: *\\"If you were truly my friends, you would not have let them confine me.\\"* The authorities eventually gave up trying to restrain him."}],"legacy":["Al-Shibli represents the extreme pole of ecstatic Sufism — the saint whose inner experience so overwhelms outward convention that he appears mad to the world. His story serves as a foil to Junaid's sobriety and raises the perennial question: is the truly intoxicated mystic above or below social norms?"],"sources":[{"label":"Wikipedia – Al-Shibli","url":"https://en.wikipedia.org/wiki/Abu_Bakr_al-Shibli","description":"Article on the former Abbasid court official who became Junaid's student and whose ecstatic states led to repeated confinement in the bimaristan","unverified":false},{"label":"Wikipedia – Junayd al-Baghdadi","url":"https://en.wikipedia.org/wiki/Junayd_of_Baghdad","description":"Al-Shibli's teacher, whose \\"sober\\" approach contrasts with al-Shibli's ecstatic \\"madness\\"","unverified":false},{"label":"Classical text","url":null,"description":"preserves al-Shibli's sayings and accounts of his relationship with al-Hallaj","unverified":false}]},{"number":18,"part":2,"slug":"abu-talib-al-makki","name":"Abu Talib al-Makki","arabicName":"أبو طالب المكي","metadata":{"fullName":"Abu Talib Muhammad ibn Ali ibn Atiyya al-Harithi al-Makki","born":"Jibal region (western Iran)","died":"386 AH / 996 CE, Baghdad","sufiOrder":"Pre-tariqa era","Major Work":"Qut al-Qulub fi Mu'amalat al-Mahbub (Nourishment of Hearts in Dealing with the Beloved)"},"ceYear":0,"biography":["Abu Talib al-Makki was one of the great systematizers of Sufi ethics and practice. Born in the Jibal region, he lived in Mecca (hence \\"al-Makki\\") before settling in Baghdad. His masterwork, Qut al-Qulub, is a comprehensive guide to the spiritual life that covers everything from the etiquette of eating and sleeping to the highest states of divine knowledge.","The Qut al-Qulub is organized around the principle that the spiritual path must be grounded in the Sharia — the external law — before ascending to the haqiqa — the inner reality. This structure deeply influenced Abu Hamid al-Ghazali's later and more famous Ihya Ulum al-Din."],"keyTeachings":["Al-Makki taught that the spiritual path is not separate from daily life but is embedded in it. Every action — eating, sleeping, working, socializing — can be transformed into worship through proper intention and awareness. His approach was practical and accessible, bringing Sufi teachings out of the exclusive circles of masters and into the lives of ordinary believers."],"legacy":["Qut al-Qulub became one of the most influential Sufi texts in history, primarily through its effect on al-Ghazali. When al-Ghazali composed his monumental Ihya, he drew extensively from al-Makki's work. Thus, al-Makki's influence — though often unrecognized — permeates the entire later tradition."],"sources":[{"label":"Wikipedia – Abu Talib al-Makki","url":"https://en.wikipedia.org/wiki/Abu_Talib_al-Makki","description":"Article on the Sufi systematizer and author of Qut al-Qulub, his life in Mecca and Baghdad, and his decisive influence on al-Ghazali","unverified":false},{"label":"Wikipedia – Al-Ghazali","url":"https://en.wikipedia.org/wiki/Al-Ghazali","description":"The 5th-century AH scholar whose *Ihya Ulum al-Din* drew heavily from al-Makki's framework","unverified":false},{"label":"Classical text","url":null,"description":"comprehensive guide to the spiritual life integrating Sharia and haqiqa; a primary source for both Sufi practice and its influence on al-Ghazali","unverified":false}]},{"number":19,"part":2,"slug":"abu-nasr-al-sarraj","name":"Abu Nasr al-Sarraj","arabicName":"أبو نصر السراج","metadata":{"fullName":"Abu Nasr Abdullah ibn Ali al-Sarraj al-Tusi","born":"Tus, Khorasan","died":"378 AH / 988 CE, Tus","sufiOrder":"Pre-tariqa era","Major Work":"Kitab al-Luma' fi al-Tasawwuf (The Book of Flashes on Sufism)"},"ceYear":0,"biography":["Abu Nasr al-Sarraj was the author of one of the earliest and most important systematic manuals of Sufism, the Kitab al-Luma'. Born in the great scholarly city of Tus in Khorasan, he traveled widely to gather teachings from Sufi masters across the Muslim world.","The Kitab al-Luma' is invaluable as a primary source. It systematically classifies the states (ahwal), stations (maqamat), and technical vocabulary of the Sufi path, drawing on the sayings and experiences of the early masters. It also includes a crucial defense of Sufism against its critics, arguing that genuine tasawwuf is fully rooted in the Quran, Sunnah, and the practice of the Salaf (pious predecessors)."],"keyTeachings":["Al-Sarraj distinguished carefully between stations (maqamat) — which are achieved through spiritual effort and are permanent — and states (ahwal) — which are divine gifts that come and go. This distinction became foundational to all later Sufi psychology."],"legacy":["The Kitab al-Luma' is one of the three essential early Sufi manuals (alongside al-Kalabadhi's Ta'arruf and al-Qushayri's Risala). It preserved the teachings of masters who left no written works of their own, making it an indispensable historical source."],"sources":[{"label":"Wikipedia – Abu Nasr al-Sarraj","url":"https://en.wikipedia.org/wiki/Abu_Nasr_al-Sarraj","description":"Article on the Khorasani Sufi and author of the Kitab al-Luma', one of the earliest systematic manuals of tasawwuf","unverified":true},{"label":"Wikipedia – Tus, Iran","url":"https://en.wikipedia.org/wiki/Tus,_Iran","description":"The great scholarly city in Khorasan where al-Sarraj was born and died; also the birthplace of al-Ghazali","unverified":false},{"label":"Classical text","url":null,"description":"one of the three canonical early Sufi manuals; systematically classifies spiritual states, stations, and vocabulary; includes a defense of Sufism's orthodoxy","unverified":false}]},{"number":20,"part":2,"slug":"abu-bakr-al-kalabadhi","name":"Abu Bakr al-Kalabadhi","arabicName":"أبو بكر الكلاباذي","metadata":{"fullName":"Abu Bakr Muhammad ibn Ibrahim ibn Ya'qub al-Kalabadhi al-Bukhari","born":"Bukhara","died":"380 AH / 990 CE (or 384 AH / 994 CE), Bukhara","sufiOrder":"Pre-tariqa era","Major Work":"Kitab al-Ta'arruf li-Madhhab Ahl al-Tasawwuf (Introduction to the Doctrine of the Sufis)"},"ceYear":0,"biography":["Abu Bakr al-Kalabadhi was a Hanafi scholar and Sufi from the great Central Asian city of Bukhara. His Kitab al-Ta'arruf is one of the most important early defenses of Sufi orthodoxy — a systematic argument that the doctrines of the great Sufi masters are fully compatible with the beliefs of the Ahl al-Sunna wa'l-Jama'a (mainstream Sunni Islam).","Writing in an environment where Sufism faced suspicion from some traditionalist scholars, al-Kalabadhi meticulously demonstrated that the major Sufi teachings on tawhid, fana', tawakkul, and other subjects all had sound bases in the Quran and hadith. He also compiled biographical information on major Sufi figures, making his work both a theological treatise and a historical document."],"keyTeachings":["Al-Kalabadhi emphasized that true Sufism is not antinomian (opposed to religious law) but is the inner dimension of the Sharia itself. He argued that the Sufis are the true followers of the Prophet ﷺ, not innovators or heretics."],"legacy":["The Ta'arruf served a crucial historical function: it helped establish the legitimacy of Sufism within mainstream Sunni thought at a time when that legitimacy was in question. Together with the works of al-Sarraj and later al-Qushayri, it created a \\"canon of defense\\" that shielded Sufism from its critics and paved the way for al-Ghazali's definitive reconciliation in the next century."],"sources":[{"label":"Wikipedia – Al-Kalabadhi","url":"https://en.wikipedia.org/wiki/Al-Kalabadhi","description":"Article on the Hanafi scholar from Bukhara and author of the Kitab al-Ta'arruf, one of the earliest systematic defenses of Sufi orthodoxy","unverified":true},{"label":"Wikipedia – Bukhara","url":"https://en.wikipedia.org/wiki/Bukhara","description":"The great Central Asian city of Islamic scholarship where al-Kalabadhi was born and died","unverified":false},{"label":"Classical text","url":null,"description":"systematic theological defense of Sufism demonstrating compatibility with mainstream Sunni belief; an essential primary historical document","unverified":false}]}]`);export{a as default};
